import os
import json
import pickle
import numpy as np
from pathlib import Path
from typing import Optional
from fastapi import FastAPI, UploadFile, File, HTTPException
from fastapi.responses import JSONResponse
from pydantic import BaseModel
import face_recognition
from sklearn.svm import SVC
from sklearn.preprocessing import LabelEncoder
from sklearn.calibration import CalibratedClassifierCV
import uvicorn
from datetime import datetime
import shutil
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = FastAPI(
    title="Office Facial Recognition Security System",
    description="Facial recognition API for office security with confidence scoring",
    version="1.0.0"
)

MODEL_PATH = "model/face_recognition_model.pkl"
ENCODER_PATH = "model/label_encoder.pkl"
ENCODINGS_PATH = "model/face_encodings.pkl"
TRAINING_DATA_DIR = "training_data"
UPLOAD_DIR = "uploads"

os.makedirs("model", exist_ok=True)
os.makedirs(TRAINING_DATA_DIR, exist_ok=True)
os.makedirs(UPLOAD_DIR, exist_ok=True)


class FaceRecognitionSystem:
    def __init__(self):
        self.model: Optional[CalibratedClassifierCV] = None
        self.label_encoder: Optional[LabelEncoder] = None
        self.known_encodings: list = []
        self.known_labels: list = []
        self.is_trained: bool = False
        self._load_model()

    def _load_model(self):
        try:
            if os.path.exists(MODEL_PATH) and os.path.exists(ENCODER_PATH):
                with open(MODEL_PATH, "rb") as f:
                    self.model = pickle.load(f)
                with open(ENCODER_PATH, "rb") as f:
                    self.label_encoder = pickle.load(f)
                if os.path.exists(ENCODINGS_PATH):
                    with open(ENCODINGS_PATH, "rb") as f:
                        data = pickle.load(f)
                        self.known_encodings = data["encodings"]
                        self.known_labels = data["labels"]
                self.is_trained = True
                logger.info("Model loaded successfully")
        except Exception as e:
            logger.error(f"Error loading model: {e}")
            self.is_trained = False

    def _save_model(self):
        with open(MODEL_PATH, "wb") as f:
            pickle.dump(self.model, f)
        with open(ENCODER_PATH, "wb") as f:
            pickle.dump(self.label_encoder, f)
        with open(ENCODINGS_PATH, "wb") as f:
            pickle.dump({
                "encodings": self.known_encodings,
                "labels": self.known_labels
            }, f)
        logger.info("Model saved successfully")

    def add_employee_photo(self, employee_id: str, employee_name: str, image_path: str) -> dict:
        image = face_recognition.load_image_file(image_path)
        face_locations = face_recognition.face_locations(image, model="hog")

        if len(face_locations) == 0:
            return {"success": False, "message": "No face detected in the image"}
        if len(face_locations) > 1:
            return {"success": False, "message": f"Multiple faces ({len(face_locations)}) detected. Please provide a photo with a single face."}

        encodings = face_recognition.face_encodings(image, face_locations)
        encoding = encodings[0]

        label = f"{employee_id}_{employee_name}"

        employee_dir = os.path.join(TRAINING_DATA_DIR, label)
        os.makedirs(employee_dir, exist_ok=True)

        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        dest_path = os.path.join(employee_dir, f"{timestamp}.jpg")
        shutil.copy2(image_path, dest_path)

        self.known_encodings.append(encoding)
        self.known_labels.append(label)

        return {
            "success": True,
            "message": f"Photo added for employee {employee_name} (ID: {employee_id})",
            "face_location": face_locations[0],
            "total_photos_for_employee": self.known_labels.count(label)
        }

    def train(self) -> dict:
        if len(self.known_encodings) == 0:
            # Try to load from training data directory
            self._load_training_data_from_disk()

        if len(self.known_encodings) < 2:
            return {"success": False, "message": "Need at least 2 face encodings to train"}

        unique_labels = set(self.known_labels)
        if len(unique_labels) < 2:
            return {"success": False, "message": "Need at least 2 different employees to train"}

        self.label_encoder = LabelEncoder()
        encoded_labels = self.label_encoder.fit_transform(self.known_labels)

        X = np.array(self.known_encodings)
        y = encoded_labels

        base_svm = SVC(kernel="rbf", probability=False, C=10.0, gamma="scale")
        self.model = CalibratedClassifierCV(base_svm, cv=min(3, min(np.bincount(y))))

        try:
            self.model.fit(X, y)
        except ValueError:
            # If cross-validation fails due to small dataset, use prefit approach
            base_svm_prob = SVC(kernel="rbf", probability=True, C=10.0, gamma="scale")
            base_svm_prob.fit(X, y)
            self.model = base_svm_prob

        self.is_trained = True
        self._save_model()

        return {
            "success": True,
            "message": "Model trained successfully",
            "num_employees": len(unique_labels),
            "num_photos": len(self.known_encodings),
            "employees": list(unique_labels)
        }

    def _load_training_data_from_disk(self):
        self.known_encodings = []
        self.known_labels = []

        training_path = Path(TRAINING_DATA_DIR)
        if not training_path.exists():
            return

        for employee_dir in training_path.iterdir():
            if not employee_dir.is_dir():
                continue

            label = employee_dir.name
            for image_file in employee_dir.iterdir():
                if image_file.suffix.lower() in [".jpg", ".jpeg", ".png", ".bmp"]:
                    try:
                        image = face_recognition.load_image_file(str(image_file))
                        encodings = face_recognition.face_encodings(image)
                        if len(encodings) > 0:
                            self.known_encodings.append(encodings[0])
                            self.known_labels.append(label)
                            logger.info(f"Loaded encoding for {label} from {image_file.name}")
                    except Exception as e:
                        logger.warning(f"Error processing {image_file}: {e}")

        logger.info(f"Loaded {len(self.known_encodings)} encodings for {len(set(self.known_labels))} employees")

    def recognize(self, image_path: str) -> dict:
        if not self.is_trained:
            return {"success": False, "message": "Model not trained yet. Please train first."}

        image = face_recognition.load_image_file(image_path)
        face_locations = face_recognition.face_locations(image, model="hog")

        if len(face_locations) == 0:
            return {
                "success": False,
                "message": "No face detected in the image",
                "faces": []
            }

        face_encodings = face_recognition.face_encodings(image, face_locations)

        results = []
        for idx, (encoding, location) in enumerate(zip(face_encodings, face_locations)):
            encoding_array = np.array(encoding).reshape(1, -1)

            probabilities = self.model.predict_proba(encoding_array)[0]
            class_labels = self.label_encoder.classes_

            probability_distribution = {}
            for label, prob in zip(class_labels, probabilities):
                parts = label.split("_", 1)
                employee_id = parts[0]
                employee_name = parts[1] if len(parts) > 1 else "Unknown"
                probability_distribution[label] = {
                    "employee_id": employee_id,
                    "employee_name": employee_name,
                    "confidence": round(float(prob), 6),
                    "confidence_percentage": round(float(prob) * 100, 2)
                }

            sorted_distribution = dict(
                sorted(probability_distribution.items(),
                       key=lambda x: x[1]["confidence"],
                       reverse=True)
            )

            best_match_label = class_labels[np.argmax(probabilities)]
            best_confidence = float(np.max(probabilities))

            # Distance-based verification
            distances = face_recognition.face_distance(
                np.array(self.known_encodings), encoding
            )
            min_distance = float(np.min(distances))

            # Determine if this is a known or unknown person
            CONFIDENCE_THRESHOLD = 0.45
            DISTANCE_THRESHOLD = 0.6

            is_known = best_confidence >= CONFIDENCE_THRESHOLD and min_distance <= DISTANCE_THRESHOLD

            best_parts = best_match_label.split("_", 1)

            face_result = {
                "face_index": idx,
                "face_location": {
                    "top": location[0],
                    "right": location[1],
                    "bottom": location[2],
                    "left": location[3]
                },
                "is_recognized": is_known,
                "best_match": {
                    "label": best_match_label,
                    "employee_id": best_parts[0],
                    "employee_name": best_parts[1] if len(best_parts) > 1 else "Unknown",
                    "confidence": round(best_confidence, 6),
                    "confidence_percentage": round(best_confidence * 100, 2),
                    "face_distance": round(min_distance, 6)
                },
                "security_assessment": {
                    "access_recommendation": "GRANT" if is_known and best_confidence >= 0.6 else
                                             "REVIEW" if is_known else "DENY",
                    "confidence_threshold": CONFIDENCE_THRESHOLD,
                    "distance_threshold": DISTANCE_THRESHOLD,
                    "risk_level": "LOW" if best_confidence >= 0.7 else
                                  "MEDIUM" if best_confidence >= 0.5 else "HIGH"
                },
                "probability_distribution": sorted_distribution,
                "statistics": {
                    "max_confidence": round(best_confidence, 6),
                    "min_confidence": round(float(np.min(probabilities)), 6),
                    "mean_confidence": round(float(np.mean(probabilities)), 6),
                    "std_confidence": round(float(np.std(probabilities)), 6),
                    "entropy": round(float(-np.sum(probabilities * np.log(probabilities + 1e-10))), 6),
                    "num_classes": len(class_labels),
                    "min_face_distance": round(min_distance, 6)
                }
            }

            results.append(face_result)

        return {
            "success": True,
            "timestamp": datetime.now().isoformat(),
            "num_faces_detected": len(face_locations),
            "faces": results
        }

    def get_employees(self) -> dict:
        unique_labels = list(set(self.known_labels))
        employees = []
        for label in unique_labels:
            parts = label.split("_", 1)
            count = self.known_labels.count(label)
            employees.append({
                "label": label,
                "employee_id": parts[0],
                "employee_name": parts[1] if len(parts) > 1 else "Unknown",
                "num_photos": count
            })
        return {
            "total_employees": len(unique_labels),
            "total_photos": len(self.known_encodings),
            "employees": employees,
            "model_trained": self.is_trained
        }

    def remove_employee(self, employee_label: str) -> dict:
        indices_to_remove = [
            i for i, label in enumerate(self.known_labels) if label == employee_label
        ]
        if not indices_to_remove:
            return {"success": False, "message": f"Employee {employee_label} not found"}

        for idx in sorted(indices_to_remove, reverse=True):
            self.known_encodings.pop(idx)
            self.known_labels.pop(idx)

        employee_dir = os.path.join(TRAINING_DATA_DIR, employee_label)
        if os.path.exists(employee_dir):
            shutil.rmtree(employee_dir)

        self.is_trained = False

        return {
            "success": True,
            "message": f"Removed {len(indices_to_remove)} photos for {employee_label}. Please retrain the model.",
            "removed_count": len(indices_to_remove)
        }


# Initialize the system
face_system = FaceRecognitionSystem()


