async def recognize_face(photo: UploadFile = File(...)):
    if not photo.content_type or not photo.content_type.startswith("image/"):
        raise HTTPException(status_code=400, detail="File must be an image")

    if not face_system.is_trained:
        raise HTTPException(
            status_code=400,
            detail="Model not trained yet. Please enroll employees and train the model first."
        )

    timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    upload_path = os.path.join(UPLOAD_DIR, f"recognize_{timestamp}_{photo.filename}")

    try:
        with open(upload_path, "wb") as f:
            content = await photo.read()
            f.write(content)

        result = face_system.recognize(upload_path)

        if not result["success"]:
            raise HTTPException(status_code=400, detail=result["message"])

        return JSONResponse(content=result)

    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"Error recognizing face: {e}")
        raise HTTPException(status_code=500, detail=str(e))
    finally:
        if os.path.exists(upload_path):
            os.remove(upload_path)


