@app.post("/verify")
async def verify_employee(
    employee_id: str,
    employee_name: str,
    photo: UploadFile = File(...)
):
    """Verify if a photo matches a specific employee."""
    if not face_system.is_trained:
        raise HTTPException(
            status_code=400,
            detail="Model not trained yet."
        )

    timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    upload_path = os.path.join(UPLOAD_DIR, f"verify_{timestamp}_{photo.filename}")

    try:
        with open(upload_path, "wb") as f:
            content = await photo.read()
            f.write(content)

        result = face_system.recognize(upload_path)

        if not result["success"]:
            raise HTTPException(status_code=400, detail=result["message"])

        target_label = f"{employee_id}_{employee_name}"

        verification_results = []
        for face in result["faces"]:
            dist = face["probability_distribution"]
            if target_label in dist:
                target_confidence = dist[target_label]["confidence"]
                is_match = target_confidence >= 0.5
            else:
                target_confidence = 0.0
                is_match = False

            verification_results.append({
                "face_index": face["face_index"],
                "face_location": face["face_location"],
                "target_employee": target_label,
                "is_match": is_match,
                "confidence": round(target_confidence, 6),
                "confidence_percentage": round(target_confidence * 100, 2),
                "best_match": face["best_match"],
                "full_distribution": face["probability_distribution"]
            })

        return JSONResponse(content={
            "success": True,
            "timestamp": datetime.now().isoformat(),
            "verification_target": target_label,
            "num_faces": len(verification_results),
            "results": verification_results
        })

    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"Error verifying face: {e}")
        raise HTTPException(status_code=500, detail=str(e))
    finally:
        if os.path.exists(upload_path):
            os.remove(upload_path)


